<template>
  <div class="user-detail-container" v-loading="loading">
    <!-- 返回按钮 -->
    <div class="back-bar">
      <el-button type="text" icon="el-icon-arrow-left" @click="$router.back()">
        返回用户列表
      </el-button>
    </div>

    <!-- 用户信息卡片 -->
    <el-card shadow="never" class="profile-card">
      <div class="profile-header">
        <div class="profile-avatar">
          <el-avatar :size="88" :src="user.avatar">
            {{ avatarInitial }}
          </el-avatar>
        </div>
        <div class="profile-meta">
          <div class="profile-name-row">
            <span class="profile-nickname">{{ user.nickname || user.username || '--' }}</span>
            <el-tag
              v-if="user.levelName"
              :color="levelTagColor"
              effect="dark"
              size="small"
              class="level-tag"
            >
              {{ user.levelName }}
            </el-tag>
          </div>
          <div class="profile-extra">
            <span class="profile-item">
              <i class="el-icon-user"></i>
              用户名：{{ user.username || '--' }}
            </span>
            <span class="profile-item">
              <i class="el-icon-mobile-phone"></i>
              {{ user.phone || '未绑定手机' }}
            </span>
          </div>
          <div class="profile-extra">
            <span class="profile-item">
              <i class="el-icon-date"></i>
              注册时间：{{ user.registerTime || '--' }}
            </span>
            <span class="profile-item">
              <i class="el-icon-star-on"></i>
              积分：{{ user.points || 0 }}
            </span>
          </div>
        </div>
        <div class="profile-actions">
          <el-button
            v-if="!user.isBlacklisted"
            type="danger"
            plain
            size="small"
            icon="el-icon-lock"
            @click="handleBlacklist(true)"
          >
            拉黑
          </el-button>
          <el-button
            v-else
            type="success"
            plain
            size="small"
            icon="el-icon-unlock"
            @click="handleBlacklist(false)"
          >
            取消拉黑
          </el-button>
        </div>
      </div>

      <el-divider />

      <!-- 统计小面板 -->
      <el-row :gutter="24" class="stat-row">
        <el-col :span="6">
          <div class="stat-item">
            <div class="stat-num">{{ formatInteger(user.orderCount) }}</div>
            <div class="stat-label">累计订单</div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="stat-item">
            <div class="stat-num">¥{{ formatNumber(user.totalSpend) }}</div>
            <div class="stat-label">消费总额</div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="stat-item">
            <div class="stat-num">{{ user.points || 0 }}</div>
            <div class="stat-label">可用积分</div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="stat-item">
            <div class="stat-num">{{ user.couponCount || 0 }}</div>
            <div class="stat-label">优惠券</div>
          </div>
        </el-col>
      </el-row>
    </el-card>

    <!-- 订单列表 -->
    <el-card shadow="never" class="section-card">
      <div slot="header" class="section-header">
        <span class="section-title">订单记录</span>
      </div>
      <el-table
        :data="orderList"
        stripe
        size="small"
        v-loading="orderLoading"
        empty-text="暂无订单记录"
      >
        <el-table-column prop="orderNumber" label="订单号" min-width="180" show-overflow-tooltip />
        <el-table-column label="金额" width="120" align="right">
          <template slot-scope="{ row }">
            <span class="table-amount">¥{{ formatNumber(row.totalAmount) }}</span>
          </template>
        </el-table-column>
        <el-table-column label="状态" width="100" align="center">
          <template slot-scope="{ row }">
            <el-tag :type="orderStatusTag(row.status)" size="mini" effect="plain">
              {{ orderStatusText(row.status) }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="createTime" label="下单时间" width="170" />
        <el-table-column label="操作" width="80" align="center" fixed="right">
          <template slot-scope="{ row }">
            <el-button
              type="text"
              size="mini"
              class="link-btn"
              @click="$router.push(`/order/detail/${row.id}`)"
            >
              查看
            </el-button>
          </template>
        </el-table-column>
      </el-table>
      <div class="pagination-wrap" v-if="orderTotal > 0">
        <el-pagination
          background
          small
          layout="prev, pager, next, total"
          :total="orderTotal"
          :page-size="orderPageSize"
          :current-page.sync="orderPage"
          @current-change="fetchOrders"
        />
      </div>
    </el-card>

    <!-- 收货地址 -->
    <el-card shadow="never" class="section-card">
      <div slot="header" class="section-header">
        <span class="section-title">收货地址</span>
      </div>
      <div v-if="addressList.length > 0" class="address-grid">
        <div
          v-for="addr in addressList"
          :key="addr.id"
          class="address-card"
          :class="{ 'is-default': addr.isDefault }"
        >
          <div class="addr-line addr-contact">
            <span class="addr-name">{{ addr.name }}</span>
            <span class="addr-phone">{{ addr.phone }}</span>
            <el-tag v-if="addr.isDefault" size="mini" type="success" effect="plain">
              默认
            </el-tag>
          </div>
          <div class="addr-line addr-full">
            {{ addr.province }}{{ addr.city }}{{ addr.district }}{{ addr.detail }}
          </div>
        </div>
      </div>
      <div v-else class="empty-block">
        <i class="el-icon-location-outline"></i>
        <p>暂无收货地址</p>
      </div>
    </el-card>
  </div>
</template>

<script>
import userApi from '@/api/user'
import orderApi from '@/api/order'

const ORDER_STATUS = {
  0: '已取消',
  10: '待付款',
  20: '待发货',
  30: '已发货',
  40: '已完成'
}

const ORDER_TAG_TYPE = {
  0: 'danger',
  10: 'info',
  20: 'warning',
  30: '',
  40: 'success'
}

export default {
  name: 'UserDetail',

  data() {
    return {
      loading: false,
      userId: null,

      user: {
        id: null,
        avatar: '',
        username: '',
        nickname: '',
        phone: '',
        registerTime: '',
        levelName: '',
        points: 0,
        orderCount: 0,
        totalSpend: 0,
        couponCount: 0,
        isBlacklisted: false
      },

      // 订单
      orderList: [],
      orderTotal: 0,
      orderPage: 1,
      orderPageSize: 10,
      orderLoading: false,

      // 地址
      addressList: []
    }
  },

  computed: {
    avatarInitial() {
      const name = this.user.nickname || this.user.username || '?'
      return name.charAt(0).toUpperCase()
    },

    levelTagColor() {
      const m = {
        '普通会员': '#909399',
        '银卡会员': '#9c6e21',
        '金卡会员': '#c9953b',
        '钻石会员': '#409EFF'
      }
      return m[this.user.levelName] || '#9c6e21'
    }
  },

  created() {
    this.userId = this.$route.params.id
    if (!this.userId) {
      this.$message.error('用户ID无效')
      this.$router.replace('/user/list')
      return
    }
    this.init()
  },

  methods: {
    async init() {
      this.loading = true
      try {
        await Promise.all([
          this.fetchUserDetail(),
          this.fetchAddresses()
        ])
        this.fetchOrders()
      } finally {
        this.loading = false
      }
    },

    // ---- 用户详情 ----
    async fetchUserDetail() {
      try {
        const res = await userApi.getUserDetail(this.userId)
        if (res.code === 0 && res.data) {
          const d = res.data
          this.user = {
            id: d.id,
            avatar: d.avatar || '',
            username: d.username || '',
            nickname: d.nickname || '',
            phone: d.phone || '',
            registerTime: d.registerTime || d.createTime || '',
            levelName: d.levelName || d.level || '',
            points: d.points || 0,
            orderCount: d.orderCount || 0,
            totalSpend: d.totalSpend || d.spendAmount || 0,
            couponCount: d.couponCount || 0,
            isBlacklisted: d.isBlacklisted || d.blacklisted || false
          }
        } else {
          this.$message.error(res.message || '获取用户详情失败')
        }
      } catch (err) {
        console.error('获取用户详情异常:', err)
        this.$message.error('获取数据失败，请稍后重试')
      }
    },

    // ---- 订单列表 ----
    async fetchOrders() {
      this.orderLoading = true
      try {
        const params = {
          userId: this.userId,
          page: this.orderPage,
          pageSize: this.orderPageSize
        }
        const res = await orderApi.getList(params)
        if (res.code === 0 && res.data) {
          this.orderList = res.data.list || res.data.records || []
          this.orderTotal = res.data.total || 0
        } else {
          this.orderList = []
          this.orderTotal = 0
        }
      } catch (err) {
        console.error('获取用户订单异常:', err)
        this.$message.error('获取数据失败，请稍后重试')
        this.orderList = []
      } finally {
        this.orderLoading = false
      }
    },

    // ---- 收货地址 ----
    async fetchAddresses() {
      try {
        const res = await userApi.getUserAddresses(this.userId)
        if (res.code === 0 && res.data) {
          this.addressList = Array.isArray(res.data) ? res.data : (res.data.list || [])
        } else {
          this.addressList = []
        }
      } catch (err) {
        console.error('获取收货地址异常:', err)
        this.$message.error('获取数据失败，请稍后重试')
        this.addressList = []
      }
    },

    // ---- 拉黑 / 取消拉黑 ----
    handleBlacklist(toBlack) {
      const tip = toBlack
        ? '确定将该用户拉黑吗？拉黑后用户将无法登录和使用小程序。'
        : '确定将该用户从黑名单中移除吗？'

      this.$confirm(tip, toBlack ? '拉黑确认' : '取消拉黑', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: toBlack ? 'warning' : 'info'
      })
        .then(async () => {
          try {
            let res
            if (toBlack) {
              res = await userApi.addToBlacklist(this.userId, { reason: '管理员操作' })
            } else {
              res = await userApi.removeFromBlacklist(this.userId)
            }
            if (res.code === 0) {
              this.$message.success(toBlack ? '已拉黑该用户' : '已取消拉黑')
              this.user.isBlacklisted = toBlack
            } else {
              this.$message.error(res.message || '操作失败')
            }
          } catch (err) {
            console.error('拉黑操作异常:', err)
            this.$message.error('操作失败，请重试')
          }
        })
        .catch(() => {})
    },

    // ---- 工具 ----
    formatNumber(val) {
      if (val == null) return '0.00'
      return Number(val).toLocaleString('zh-CN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })
    },

    formatInteger(val) {
      if (val == null) return '0'
      return Number(val).toLocaleString('zh-CN')
    },

    orderStatusText(status) {
      return ORDER_STATUS[status] || '未知'
    },

    orderStatusTag(status) {
      return ORDER_TAG_TYPE[status] || 'info'
    }
  }
}
</script>

